const plan = $items('Read Content Plan').map(i => i.json);
const queue = $items('Read Queue').map(i => i.json);
const batchSize = $('Globals').first().json.BATCH_SIZE || 2;
const lookback = $('Globals').first().json.DEDUP_LOOKBACK || 50;

const planned = plan.filter(r => r.status === 'planned');
if (planned.length === 0) throw new Error('No concepts with status "planned" in content_plan. Run the Planner (A2) first.');

const batch = planned.slice(0, batchSize);

const recent = queue
  .filter(r => r.created_at)
  .sort((a, b) => String(b.created_at).localeCompare(String(a.created_at)))
  .slice(0, lookback)
  .map(r => ({ title: r.title || '', summary: r.one_line_summary || '' }));

return batch.map((c, i) => ({
  json: {
    slot: i + 1,
    drive_file_id: c.drive_file_id,
    book_title: c.book_title,
    book_author: c.book_author,
    chapter_number: c.chapter_number,
    chapter_title: c.chapter_title,
    start_page: c.start_page,
    end_page: c.end_page,
    concept_index: c.concept_index,
    concept_title: c.concept_title,
    angle: c.angle,
    brief: c.brief,
    dedup_context: recent,
    retry_count: 0,
    avoid_angles: []
  }
}));

const all = $input.all().map(i => i.json);
const seen = new Set();
const uniqueBooks = [];
for (const c of all) {
  if (!seen.has(c.drive_file_id)) {
    seen.add(c.drive_file_id);
    uniqueBooks.push({ json: { drive_file_id: c.drive_file_id, book_title: c.book_title } });
  }
}
return uniqueBooks;

const raw = $json.text || $json.data || '';
let pages = [];
if (Array.isArray(raw)) pages = raw;
else if (typeof raw === 'string') {
  pages = raw.split('\f');
  if (pages.length < 3) pages = raw.split(/\n\s*\n\s*\n/);
}
const book = $('Loop Books').item.json;
return [{ json: { drive_file_id: book.drive_file_id, book_title: book.book_title, pages } }];

const bookItems = $items('Normalize Book Pages');
const cache = {};
for (const it of bookItems) {
  cache[it.json.drive_file_id] = it.json.pages;
}

const concepts = $items('Select Batch').map(i => i.json);
const out = [];
for (const c of concepts) {
  const pages = cache[c.drive_file_id] || [];
  const start = Math.max(0, (c.start_page || 1) - 1);
  const end = Math.min(pages.length, c.end_page || pages.length);
  const chapterText = pages.slice(start, end).join('\n\n').slice(0, 25000);
  out.push({ json: { ...c, chapter_text: chapterText } });
}
return out;

