let idea;
try { idea = JSON.parse(cleaned); } catch (e) { throw new Error('Dialogue JSON parse failed: ' + e.message); }
if (!Array.isArray(idea.lines) || idea.lines.length < 2) throw new Error('Dialogue must have >= 2 lines');
const ctx = $('Loop Each Concept').item.json;
const fullScript = idea.lines.map(l => `${l.speaker}: ${l.text}`).join('\n');
const spokenOnly = idea.lines.map(l => l.text).join(' ');
return [{
  json: {
    ...ctx,
    chapter_text: undefined,
    idea_title: idea.title,
    idea_hook: idea.lines[0].text,
    idea_one_line_summary: idea.oneLineSummary,
    idea_lines: idea.lines,
    idea_full_script: fullScript,
    idea_spoken_text: spokenOnly,
    idea_on_screen_caption: idea.onScreenCaption,
    idea_viral_score: idea.viralScore,
    idea_keywords: idea.keywords || [],
    idea_word_count: spokenOnly.split(/\s+/).length
  }
}];

