const raw = $json.output || '';
const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
let dedup;
try { dedup = JSON.parse(cleaned); } catch (e) { dedup = { duplicate: false, similar_to: null, reason: 'parse-failed' }; }
const prev = $('Parse Dialogue').item.json;
const minScore = $('Globals').first().json.MIN_VIRAL_SCORE || 7;
const maxRetries = $('Globals').first().json.DEDUP_MAX_RETRIES || 2;
const isDup = dedup.duplicate === true;
const lowScore = Number(prev.idea_viral_score || 0) < minScore;
const needsRetry = (isDup || lowScore) && (prev.retry_count || 0) < maxRetries;
let avoid = Array.isArray(prev.avoid_angles) ? [...prev.avoid_angles] : [];
if (isDup || lowScore) {
  avoid.push({ title: prev.idea_title, summary: prev.idea_one_line_summary, reason: isDup ? 'duplicate of ' + (dedup.similar_to || 'past') : 'viral score too low' });
}
return [{
  json: {
    ...prev,
    dedup_result: dedup,
    is_duplicate: isDup,
    needs_retry: needsRetry,
    retry_count: (prev.retry_count || 0) + (needsRetry ? 1 : 0),
    avoid_angles: avoid,
    skip_concept: (isDup || lowScore) && !needsRetry
  }
}];

const prev = $json;
const lines = prev.idea_lines || [];
return lines.map((l, i) => ({
  json: {
    _parent: { ...prev, idea_lines: undefined },
    line_index: i,
    speaker: l.speaker,
    text: l.text,
    voice_id: l.speaker === 'A' ? $('Globals').first().json.CHARACTER_A_VOICE_ID : $('Globals').first().json.CHARACTER_B_VOICE_ID
  }
}));

// Estimate audio duration from binary size (no fs / ffprobe)
// and generate evenly distributed word timings

const lineCtx = $('Fan Out Lines').item.json;

// Get binary data from ElevenLabs node
const binaryProps = Object.keys($binary || {});
if (binaryProps.length === 0) {
  throw new Error('No binary attached to item from ElevenLabs node.');
}

const binKey = binaryProps[0];
const bin = $binary[binKey];

if (!bin || !bin.data) {
  throw new Error('Binary key ' + binKey + ' has no data');
}

// Generate run ID (kept from your original logic)
const runId = ($execution.id || ('r' + Date.now())) + '_s' + (lineCtx._parent?.slot || 0);

// --- Duration estimation (replaces ffprobe) ---
const buffer = Buffer.from(bin.data, 'base64');
const byteLength = buffer.length;

// You used: mp3_44100_128 → 128 kbps
const bitrate = 128000; // bits per second

let duration = (byteLength * 8) / bitrate;

// Fallback safety (in case something weird happens)
if (!duration || duration <= 0) {
  const wc = (lineCtx.text || '').trim().split(/\s+/).length;
  duration = Math.max(1.0, wc / 2.5);
}

// --- Word timing synthesis ---
const words = (lineCtx.text || '').trim().split(/\s+/).filter(Boolean);

const perWord = words.length > 0 ? duration / words.length : 0;

const word_timings = words.map((w, i) => ({
  word: w,
  start: +(i * perWord).toFixed(3),
  end: +((i + 1) * perWord).toFixed(3)
}));

// Return WITHOUT filesystem path (since we didn't save file)
return [{
  json: {
    _parent: lineCtx._parent,
    line_index: lineCtx.line_index,
    speaker: lineCtx.speaker,
    text: lineCtx.text,
    duration,
    word_timings,
    run_id: runId
  },
  binary: {
    [binKey]: bin // keep audio attached for next nodes
  }
}];

const fs = require('fs');
const path = require('path');

const arr = ($json.line_index || []).map((idx, i) => ({
  idx,
  speaker: $json.speaker[i],
  text: $json.text[i],
  duration: $json.duration[i],
  words: $json.word_timings[i],
  audio_path: $json.audio_path[i]
}));
arr.sort((a, b) => a.idx - b.idx);

const parent = $items('Save Line Audio + Timings')[0].json._parent;
const runId = $items('Save Line Audio + Timings')[0].json.run_id;
const workDir = $('Globals').first().json.WORK_DIR;
const font = $('Globals').first().json.CAPTION_FONT || 'Arial';

let offset = 0;
const spriteA = [];
const spriteB = [];
const globalWords = [];
for (const line of arr) {
  const winStart = offset;
  const winEnd = offset + line.duration;
  if (line.speaker === 'A') spriteA.push([winStart, winEnd]);
  else spriteB.push([winStart, winEnd]);
  for (const w of (line.words || [])) {
    if (w.start == null || w.end == null) continue;
    globalWords.push({ word: w.word, start: offset + w.start, end: offset + w.end });
  }
  offset += line.duration;
}
const totalDuration = offset;

function assTime(t) {
  const h = Math.floor(t / 3600);
  const m = Math.floor((t % 3600) / 60);
  const s = Math.floor(t % 60);
  const cs = Math.floor((t - Math.floor(t)) * 100);
  return `${h}:${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}.${String(cs).padStart(2,'0')}`;
}
const assHeader = `[Script Info]\nScriptType: v4.00+\nPlayResX: 720\nPlayResY: 1280\n\n[V4+ Styles]\nFormat: Name, Fontname, Fontsize, PrimaryColour, OutlineColour, BackColour, Bold, Outline, Shadow, Alignment, MarginL, MarginR, MarginV\nStyle: Cap,${font},64,&H00FFFFFF,&H00000000,&H00000000,1,6,0,2,40,40,260\n\n[Events]\nFormat: Layer, Start, End, Style, Text\n`;
const dialogueLines = globalWords.map(w => {
  const txt = String(w.word).replace(/[{}]/g, '');
  return `Dialogue: 0,${assTime(w.start)},${assTime(w.end)},Cap,,0,0,0,,${txt.toUpperCase()}`;
}).join('\n');
const assPath = path.join(workDir, `${runId}_captions.ass`);
fs.writeFileSync(assPath, assHeader + dialogueLines + '\n');

const listPath = path.join(workDir, `${runId}_concat.txt`);
fs.writeFileSync(listPath, arr.map(l => `file '${l.audio_path.replace(/'/g, "'\\''")}'`).join('\n'));
const mergedAudioPath = path.join(workDir, `${runId}_voice.mp3`);

return [{
  json: {
    ...parent,
    run_id: runId,
    total_audio_duration: totalDuration,
    sprite_a_windows: spriteA,
    sprite_b_windows: spriteB,
    ass_path: assPath,
    concat_list_path: listPath,
    merged_audio_path: mergedAudioPath
  }
}];

const fs = require('fs');
const path = require('path');
const prev = $('Build Timing + Captions').item.json;
const mcDir = $('Globals').first().json.MINECRAFT_DIR;
if (!fs.existsSync(mcDir)) throw new Error('Minecraft dir not found: ' + mcDir);
const clips = fs.readdirSync(mcDir).filter(f => /\.(mp4|mov|mkv|webm)$/i.test(f));
if (clips.length === 0) throw new Error('No video clips in ' + mcDir);
const pick = clips[Math.floor(Math.random() * clips.length)];
const clipPath = path.join(mcDir, pick);
const startOffset = Math.floor(Math.random() * 25);
const dur = prev.total_audio_duration + 0.5;
return [{ json: { ...prev, mc_clip_path: clipPath, mc_clip_name: pick, mc_start_offset: startOffset, mc_duration: dur } }];

const prev = $json;
const g = $('Globals').first().json;
const path = require('path');

const outPath = path.join(g.WORK_DIR, `${prev.run_id}_final.mp4`);

const ena = wins => wins.map(([s, e]) => `between(t,${s.toFixed(3)},${e.toFixed(3)})`).join('+');
const aEnable = ena(prev.sprite_a_windows) || '0';
const bEnable = ena(prev.sprite_b_windows) || '0';

const dur = prev.mc_duration.toFixed(3);
const musicVol = g.MUSIC_VOLUME || '0.15';

const assEsc = prev.ass_path.replace(/\\/g, '/').replace(/:/g, '\\:');

const filter = [
  `[0:v]trim=start=${prev.mc_start_offset}:duration=${dur},setpts=PTS-STARTPTS,scale=720:1280:force_original_aspect_ratio=increase,crop=720:1280[bg]`,
  `[1:v]scale=320:-1[spA]`,
  `[2:v]scale=320:-1[spB]`,
  `[bg][spA]overlay=x=20:y=H-h-340:enable='${aEnable}'[t1]`,
  `[t1][spB]overlay=x=W-w-20:y=H-h-340:enable='${bEnable}'[t2]`,
  `[t2]subtitles='${assEsc}'[vout]`,
  `[4:a]volume=${musicVol},aloop=loop=-1:size=2e9[music]`,
  `[3:a][music]amix=inputs=2:duration=first:dropout_transition=0[aout]`
].join(';');

const cmd = [
  'ffmpeg -y',
  `-stream_loop -1 -i "${prev.mc_clip_path}"`,
  `-i "${g.SPRITE_A_PATH}"`,
  `-i "${g.SPRITE_B_PATH}"`,
  `-i "${prev.merged_audio_path}"`,
  `-i "${g.MUSIC_BED_PATH}"`,
  `-filter_complex "${filter}"`,
  '-map "[vout]" -map "[aout]"',
  `-t ${dur}`,
  '-c:v libx264 -preset veryfast -crf 21 -pix_fmt yuv420p',
  '-c:a aac -b:a 192k',
  `"${outPath}"`
].join(' ');

return [{ json: { ...prev, final_video_path: outPath, ffmpeg_cmd: cmd } }];

const fs = require('fs');
const prev = $('Build FFmpeg Command').item.json;
if (!fs.existsSync(prev.final_video_path)) {
  throw new Error('FFmpeg produced no output file: ' + prev.final_video_path);
}
const stat = fs.statSync(prev.final_video_path);
if (stat.size < 100000) {
  throw new Error('FFmpeg output suspiciously small (' + stat.size + ' bytes): ' + prev.final_video_path);
}
const data = fs.readFileSync(prev.final_video_path);
return [{
  json: { ...prev, final_video_size: stat.size },
  binary: {
    video: {
      data: data.toString('base64'),
      mimeType: 'video/mp4',
      fileName: `${prev.run_id}.mp4`
    }
  }
}];

const prev = $('Load Final Video').item.json;
const driveId = $json.id;
return [{ json: { ...prev, video_drive_id: driveId, video_drive_link: `https://drive.google.com/file/d/${driveId}/view` } }];

const fs = require('fs');
const path = require('path');
const prev = $('Capture Drive Ref').item.json;
const workDir = $('Globals').first().json.WORK_DIR;
try {
  const files = fs.readdirSync(workDir).filter(f => f.startsWith(prev.run_id));
  for (const f of files) { try { fs.unlinkSync(path.join(workDir, f)); } catch (e) {} }
} catch (e) {}
return [{ json: { run_id: prev.run_id, cleaned: true, title: prev.idea_title } }];
